31	void FMHACutlassSM100FwdRun(at::Tensor workspace_buffer, at::Tensor q, at::Tensor k,
32	                            at::Tensor v, at::Tensor cumulative_seqlen_q,
33	                            at::Tensor cumulative_seqlen_kv, at::Tensor o, at::Tensor lse,
34	                            int mask_mode_code, float sm_scale, int max_seqlen_q,
35	                            int max_seqlen_kv, bool is_varlen) {
36	  const c10::cuda::OptionalCUDAGuard device_guard(q.device());
37	  CHECK(q.scalar_type() == k.scalar_type());
38	  auto scalar_type_in = q.scalar_type();
39	  auto scalar_type_out = o.scalar_type();
40	  int head_dim_qk = q.size(-1);
41	  int head_dim_vo = v.size(-1);
42	  MaskMode mask_mode = static_cast<MaskMode>(mask_mode_code);
