44	  if (scalar_type_in == at::ScalarType::BFloat16 &&
45	      scalar_type_out == at::ScalarType::BFloat16) {
46	    using Element = cutlass::bfloat16_t;
47	    using ElementOut = cutlass::bfloat16_t;
48	
49	    auto apply_config = [&](auto fn) {
50	      if (mask_mode == MaskMode::kCausal) {
51	        if (is_varlen) {
52	          fn(CausalMask<false>{}, cute::true_type{}, Element{}, ElementOut{});
53	        } else {
54	          fn(CausalMask<false>{}, cute::false_type{}, Element{}, ElementOut{});
55	        }
56	      } else {
57	        if (is_varlen) {
58	          fn(ResidualMask{}, cute::true_type{}, Element{}, ElementOut{});
59	        } else {
60	          fn(ResidualMask{}, cute::false_type{}, Element{}, ElementOut{});
61	        }
62	      }
63	    };
64	
65	    apply_config([&](auto mask, auto varlen, auto in, auto out) {
66	      if (head_dim_qk == 192 && head_dim_vo == 128) {
